async function main() {
  const base = String($env.TWENTY_INTERNAL_BASE || '').replace(/\/$/, '');
  const token = $env.TWENTY_API_KEY;
  if (!base || !token) {
    throw new Error('TWENTY_INTERNAL_BASE and TWENTY_API_KEY must be set for n8n');
  }
  const b = $input.first().json;
  const p = b.payload || {};
  const email = String(p.email || '').trim();
  const phoneE164 = String(p.phoneE164 || '').trim();
  const journeyStage = String(b.journeyStage || 'unknown').trim();
  const source = String(b.source || 'manual').trim();
  if (!email && !phoneE164) {
    return [];
  }
  const ext = p.externalId != null && p.externalId !== '' ? String(p.externalId) : '';
  const jobTitleLine = ext
    ? `Journey | ${journeyStage} | ${source} | ext:${ext}`
    : `Journey | ${journeyStage} | ${source}`;
  const authHeaders = {
    Authorization: `Bearer ${token}`,
    'Content-Type': 'application/json',
  };
  async function findByEmail() {
    if (!email) return null;
    const filter = `emails.primaryEmail[eq]:${email}`;
    const url = `${base}/rest/people?filter=${encodeURIComponent(filter)}&limit=1`;
    const r = await this.helpers.httpRequest({ method: 'GET', url, headers: authHeaders, json: true });
    const people = r && r.data && Array.isArray(r.data.people) ? r.data.people : [];
    return people[0] || null;
  }
  async function findByPhone() {
    if (!phoneE164) return null;
    const filter = `phones.primaryPhoneNumber[eq]:${phoneE164}`;
    const url = `${base}/rest/people?filter=${encodeURIComponent(filter)}&limit=1`;
    const r = await this.helpers.httpRequest({ method: 'GET', url, headers: authHeaders, json: true });
    const people = r && r.data && Array.isArray(r.data.people) ? r.data.people : [];
    return people[0] || null;
  }
  const existing = (await findByEmail.call(this)) || (await findByPhone.call(this));
  if (existing && existing.id) {
    const prior = String(existing.jobTitle || '').trim();
    const mergedJobTitle = prior ? `${prior} | ${jobTitleLine}` : jobTitleLine;
    const patchUrl = `${base}/rest/people/${existing.id}`;
    const patchRes = await this.helpers.httpRequest({
      method: 'PATCH',
      url: patchUrl,
      headers: authHeaders,
      body: { jobTitle: mergedJobTitle },
      json: true,
    });
    return [
      {
        json: {
          ok: true,
          action: 'updated',
          personId: existing.id,
          journeyStage,
          source,
          twenty: patchRes,
        },
      },
    ];
  }
  const firstName = String(p.firstName || '').trim() || 'Lead';
  const lastName = String(p.lastName || '').trim() || 'Prospect';
  const postBody = {
    name: { firstName, lastName },
    jobTitle: jobTitleLine,
  };
  if (email) {
    postBody.emails = { primaryEmail: email, additionalEmails: null };
  }
  if (phoneE164) {
    postBody.phones = {
      primaryPhoneNumber: phoneE164,
      primaryPhoneCountryCode: '',
      primaryPhoneCallingCode: '',
      additionalPhones: null,
    };
  }
  const postRes = await this.helpers.httpRequest({
    method: 'POST',
    url: `${base}/rest/people`,
    headers: authHeaders,
    body: postBody,
    json: true,
  });
  const data = postRes && postRes.data ? postRes.data : postRes;
  const newId = data && (data.id || (data.person && data.person.id));
  return [
    {
      json: {
        ok: true,
        action: 'created',
        personId: newId || null,
        journeyStage,
        source,
        twenty: postRes,
      },
    },
  ];
}
return await main.call(this);
